import { defineStore } from 'pinia';
import { ref } from 'vue';

export type SceneType = 'idle' | 'projects' | 'about' | 'matrix' | 'loading' | string;

export const useSceneStore = defineStore('scene', () => {
  const currentScene = ref<SceneType>('idle');
  const isLoading = ref(false);
  const sceneParams = ref<any>(null);

  function setScene(scene: SceneType, params: any = null) {
    isLoading.value = true;
    currentScene.value = 'loading';
    sceneParams.value = params;

    // Имитация загрузки ассетов Three.js
    setTimeout(() => {
      currentScene.value = scene;
      isLoading.value = false;
    }, 500);
  }

  return {
    currentScene,
    isLoading,
    sceneParams,
    setScene
  };
});

import { useTerminalStore } from '../store/useTerminalStore';
import { useSceneStore } from '../../scenes/store/useSceneStore';
import { useSettingsStore } from '@/shared/store/useSettingsStore';
import { projects } from '@/content/projects';
import { profile } from '@/content/profile';
import { courses } from '@/content/courses';
import { i18n } from '@/shared/lib/i18n';

const t = i18n.global.t;

export interface Command {
  name: string;
  description: string;
  execute: (args: string[]) => void | Promise<void>;
}

export class CommandEngine {
  private commands: Record<string, Command> = {};
  private terminalStore = useTerminalStore();
  private sceneStore = useSceneStore();
  private settingsStore = useSettingsStore();

  constructor() {
    this.registerDefaultCommands();
  }

  private registerDefaultCommands() {
    this.register({
      name: 'help',
      description: t('cmd.help.desc'),
      execute: async () => {
        await this.terminalStore.addTypewriterEntry(t('cmd.help.title'), 'system', 15);
        const sortedCommands = Object.values(this.commands).sort((a, b) => a.name.localeCompare(b.name));
        for (const cmd of sortedCommands) {
          if (this.terminalStore.skipTyping) {
             this.terminalStore.addEntry(`${cmd.name.padEnd(15)} - ${cmd.description}`, 'output');
          } else {
             await this.terminalStore.addTypewriterEntry(`${cmd.name.padEnd(15)} - ${cmd.description}`, 'output', 10);
          }
        }
      }
    });

    this.register({
      name: 'ls',
      description: t('cmd.ls.desc'),
      execute: async (args) => {
        const category = args[0]?.toLowerCase();
        if (category === 'projects') {
          await this.terminalStore.addTypewriterEntry(t('cmd.ls.projects'), 'system', 15);
          for (let i = 0; i < projects.length; i++) {
            const p = projects[i];
            if (!p) continue;
            const index = i + 1;
            await this.terminalStore.addTypewriterEntry(`${index}) ${p.name} - ${p.summary} (${p.techStack.join(', ')})`, 'output', 10);
            if (p.links.demo) await this.terminalStore.addTypewriterEntry(`   demo: ${p.links.demo}`, 'success', 5);
            if (p.links.github) await this.terminalStore.addTypewriterEntry(`   git : ${p.links.github}`, 'success', 5);
            if (p.links.case) await this.terminalStore.addTypewriterEntry(`   case: ${p.links.case}`, 'success', 5);
            this.terminalStore.addEntry('', 'output'); // Spacer
          }
          this.sceneStore.setScene('projects');
        } else if (category === 'courses') {
          await this.terminalStore.addTypewriterEntry(t('cmd.ls.courses'), 'system', 15);
          for (const c of courses) {
            const status = c.status === 'completed' ? '✓' : '…';
            await this.terminalStore.addTypewriterEntry(`${status} ${c.title.padEnd(35)} [${c.provider}]`, 'output', 10);
          }
        } else {
          this.terminalStore.addEntry(t('cmd.ls.usage'), 'warning');
        }
      }
    });

    this.register({
      name: 'open',
      description: t('cmd.open.desc'),
      execute: async (args) => {
        const slug = args[0];
        if (!slug) {
          this.terminalStore.addEntry(t('cmd.open.usage'), 'warning');
          return;
        }

        const project = projects.find(p => p.slug === slug);
        if (!project) {
          this.terminalStore.addEntry(t('errors.projectNotFound', { slug }), 'error');
          return;
        }

        await this.terminalStore.addTypewriterEntry(t('cmd.open.init', { slug }), 'system', 20);
        await this.terminalStore.addTypewriterEntry(t('cmd.open.decrypt'), 'system', 15);

        // Render Card
        await this.terminalStore.addTypewriterEntry(''.padEnd(50, '-'), 'success', 5);
        await this.terminalStore.addTypewriterEntry(`${t('cmd.open.labelName').padEnd(12)} ${project.name}`, 'success', 10);
        await this.terminalStore.addTypewriterEntry(`${t('cmd.open.labelRole').padEnd(12)} ${project.role}`, 'output', 10);
        await this.terminalStore.addTypewriterEntry(`${t('cmd.open.labelYear').padEnd(12)} ${project.year}`, 'output', 10);
        await this.terminalStore.addTypewriterEntry(`${t('cmd.open.labelStack').padEnd(12)} ${project.techStack.join(', ')}`, 'output', 10);
        await this.terminalStore.addTypewriterEntry(`${t('cmd.open.labelDesc').padEnd(12)} ${project.description}`, 'output', 10);

        if (Object.keys(project.links).length > 0) {
          await this.terminalStore.addTypewriterEntry(`${t('cmd.open.labelLinks').padEnd(12)}`, 'output', 10);
          for (const [type, url] of Object.entries(project.links)) {
            await this.terminalStore.addTypewriterEntry(`  > ${type.padEnd(8)}: ${url}`, 'success', 5);
          }
        }

        await this.terminalStore.addTypewriterEntry(''.padEnd(50, '-'), 'success', 5);

        this.terminalStore.addEntry(t('cmd.open.repo', { slug }), 'success');
        this.sceneStore.setScene(`project-${slug}`);
      }
    });

    this.register({
      name: 'links',
      description: t('cmd.links.desc'),
      execute: async (args) => {
        const slug = args[0];
        if (!slug) {
          this.terminalStore.addEntry(t('cmd.open.linksUsage'), 'warning');
          return;
        }

        const project = projects.find(p => p.slug === slug);
        if (!project) {
          this.terminalStore.addEntry(t('errors.projectNotFound', { slug }), 'error');
          return;
        }

        const linkEntries = Object.entries(project.links);
        if (linkEntries.length === 0) {
          this.terminalStore.addEntry(t('cmd.open.noLinks'), 'warning');
          return;
        }

        await this.terminalStore.addTypewriterEntry(`${t('cmd.open.labelLinks')} ${project.name}`, 'system', 15);
        for (const [type, url] of linkEntries) {
          await this.terminalStore.addTypewriterEntry(`[${type.toUpperCase()}] ${url}`, 'success', 10);
        }
      }
    });

    this.register({
      name: 'link',
      description: t('cmd.link.desc'),
      execute: async (args) => {
        const slug = args[0];
        const type = args[1]?.toLowerCase();

        if (!slug || !type) {
          this.terminalStore.addEntry(t('cmd.open.linkUsage'), 'warning');
          return;
        }

        const project = projects.find(p => p.slug === slug);
        if (!project) {
          this.terminalStore.addEntry(t('errors.projectNotFound', { slug }), 'error');
          return;
        }

        const url = (project.links as any)[type];
        if (!url) {
          this.terminalStore.addEntry(t('cmd.open.noLinks'), 'error');
          return;
        }

        this.terminalStore.addEntry(`Opening ${type} for ${slug}...`, 'success');
        window.open(url, '_blank');
      }
    });

    this.register({
      name: 'about',
      description: t('cmd.about.desc'),
      execute: async () => {
        this.sceneStore.setScene('asciiAssemble', { ascii: profile.asciiPortrait });
        await this.terminalStore.addTypewriterEntry(`${t('cmd.about.identified')} ${profile.name}`, 'success', 25);
        await this.terminalStore.addTypewriterEntry(`${t('cmd.about.role')}       ${profile.title}`, 'output', 20);
        await this.terminalStore.addTypewriterEntry(`${t('cmd.about.bio')}        ${profile.bio}`, 'output', 20);
        await this.terminalStore.addTypewriterEntry(`${t('cmd.about.skills')}     ${profile.skills.join(', ')}`, 'output', 15);
        await this.terminalStore.addTypewriterEntry(`${t('cmd.about.location')}   ${profile.location}`, 'system', 20);
        await this.terminalStore.addTypewriterEntry(`${t('cmd.about.status')}     ${profile.status}`, 'system', 20);
      }
    });

    this.register({
      name: 'teach',
      description: t('cmd.teach.desc'),
      execute: async (args) => {
        if (args[0] === 'me') {
          await this.terminalStore.addTypewriterEntry(t('cmd.teach.loading'), 'system', 20);
          await this.terminalStore.addTypewriterEntry(t('cmd.teach.fact'), 'output', 15);
        } else {
          this.terminalStore.addEntry(t('cmd.teach.usage'), 'warning');
        }
      }
    });

    this.register({
      name: 'matrix',
      description: t('cmd.matrix.desc'),
      execute: () => {
        this.terminalStore.addEntry(t('cmd.matrix.follow'), 'success');
        this.sceneStore.setScene('matrix');
      }
    });

    this.register({
      name: 'clear',
      description: t('cmd.clear.desc'),
      execute: () => {
        this.terminalStore.clearHistory();
      }
    });

    this.register({
      name: 'exit',
      description: t('cmd.exit.desc'),
      execute: async () => {
        await this.terminalStore.addTypewriterEntry(t('cmd.exit.terminating'), 'error');
        await this.terminalStore.addTypewriterEntry(t('cmd.exit.goodbye'), 'system');
        this.sceneStore.setScene('idle');
        setTimeout(() => {
          window.location.reload();
        }, 1000);
      }
    });

    this.register({
      name: 'echo',
      description: t('cmd.echo.desc'),
      execute: (args) => {
        this.terminalStore.addEntry(args.join(' '), 'output');
      }
    });

    this.register({
      name: 'lang',
      description: t('cmd.lang.desc'),
      execute: async (args) => {
        const newLang = args[0]?.toLowerCase();
        if (!newLang) {
          this.terminalStore.addEntry(t('cmd.lang.current', { lang: this.settingsStore.lang }), 'system');
          this.terminalStore.addEntry(t('cmd.lang.available'), 'output');
          return;
        }

        if (newLang === 'ru' || newLang === 'en') {
          this.settingsStore.setLang(newLang);
          await this.terminalStore.addTypewriterEntry(t('cmd.lang.changed', { lang: newLang }), 'success', 20);
        } else {
          this.terminalStore.addEntry(t('cmd.lang.usage'), 'error');
        }
      }
    });

    // --- EASTER EGGS ---
    this.register({
      name: 'senior-power',
      description: t('cmd.senior.desc'),
      execute: async () => {
        const isSenior = this.terminalStore.theme === 'senior';
        if (isSenior) {
          this.terminalStore.setTheme('default');
          await this.terminalStore.addTypewriterEntry(t('cmd.senior.deactivated'), 'system');
        } else {
          this.terminalStore.setTheme('senior');
          await this.terminalStore.addTypewriterEntry(t('cmd.senior.activated'), 'error');
          await this.terminalStore.addTypewriterEntry(t('cmd.senior.overdrive'), 'error', 10);
        }
      }
    });

    this.register({
      name: 'refactor',
      description: t('cmd.refactor.desc'),
      execute: async () => {
        await this.terminalStore.addTypewriterEntry(t('cmd.refactor.scanning'), 'system', 30);
        this.terminalStore.addEntry('[                    ] 0%', 'output');

        for (let i = 1; i <= 10; i++) {
          await new Promise(resolve => setTimeout(resolve, 200 + Math.random() * 300));
          const progress = i * 10;
          const bars = '#'.repeat(i * 2).padEnd(20, ' ');
          this.terminalStore.updateLastEntry(`[${bars}] ${progress}%`);
        }

        await this.terminalStore.addTypewriterEntry(t('cmd.refactor.complete'), 'success');
      }
    });

    this.register({
      name: 'sudo',
      description: t('cmd.sudo.desc'),
      execute: async () => {
        await this.terminalStore.addTypewriterEntry(t('cmd.sudo.denied'), 'error', 15);
      }
    });
  }

  register(command: Command) {
    this.commands[command.name.toLowerCase()] = command;
  }

  async execute(input: string) {
    const trimmedInput = input.trim();
    if (!trimmedInput) return;

    this.terminalStore.skipTyping = false;
    this.terminalStore.addEntry(`${t('terminal.prompt')} ${trimmedInput}`, 'command');
    this.terminalStore.addToCommandHistory(trimmedInput);

    const [cmdName, ...args] = trimmedInput.split(/\s+/);
    if (!cmdName) return;

    const command = this.commands[cmdName.toLowerCase()];

    if (command) {
      await command.execute(args);
    } else {
      this.terminalStore.addEntry(t('errors.unknownCommand', { cmd: cmdName }), 'error');
    }
  }

  autocomplete(input: string): string {
    if (!input) return '';

    const cmdNames = Object.keys(this.commands);
    const parts = input.trim().split(/\s+/);

    // Autocomplete command name
    if (parts.length <= 1) {
      const matches = cmdNames.filter(name => name.startsWith(input.toLowerCase()));
      if (matches.length === 1 && matches[0]) {
        return matches[0];
      }
      if (matches.length > 1) {
        this.terminalStore.addEntry(t('errors.autocompleteMatches', { matches: matches.join(', ') }), 'system');
      }
    }
    // Special case for subcommands and slugs
    else if (parts.length === 2) {
      const cmd = parts[0]?.toLowerCase();
      const arg = parts[1]?.toLowerCase();
      if (cmd === 'ls') {
        const sub = ['projects', 'courses'].find(s => s.startsWith(arg || ''));
        if (sub) return `ls ${sub}`;
      }
      if (cmd === 'open') {
        const slug = projects.map(p => p.slug).find(s => s.startsWith(arg || ''));
        if (slug) return `open ${slug}`;
      }
      if (cmd === 'teach' && 'me'.startsWith(arg || '')) return 'teach me';
    }

    return input;
  }
}

// Singleton instance
let engineInstance: CommandEngine | null = null;

export function useCommandEngine() {
  if (!engineInstance) {
    engineInstance = new CommandEngine();
  }
  return engineInstance;
}

import { defineStore } from 'pinia';
import { i18n } from '@/shared/lib/i18n';
import { detectLocale } from '@/shared/lib/i18n/detectLocale';

export const useSettingsStore = defineStore('settings', {
  state: () => ({
    lang: detectLocale()
  }),
  actions: {
    init() {
      // Set i18n locale on start (already set by detectLocale in i18n/index.ts, but sync for safety)
      (i18n.global.locale as any).value = this.lang;
    },
    setLang(newLang: 'ru' | 'en') {
      this.lang = newLang;
      localStorage.setItem('terminal.lang', newLang);
      (i18n.global.locale as any).value = newLang;
    }
  }
});

import { fileURLToPath, URL } from 'node:url'

import { defineConfig } from 'vite'
import vue from '@vitejs/plugin-vue'
import vueDevTools from 'vite-plugin-vue-devtools'

// https://vite.dev/config/
export default defineConfig(({ mode }) => {
  return {
    plugins: [
      vue(),
      mode === 'development' && vueDevTools(),
    ].filter(Boolean) as any,
    resolve: {
      alias: {
        '@': fileURLToPath(new URL('./src', import.meta.url))
      },
    },
    esbuild: {
      drop: mode === 'production' ? ['console', 'debugger'] : [],
    },
  }
})
